--
-- Table structure for table `attendance_employees`
--

DROP TABLE IF EXISTS `attendance_employees`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `attendance_employees` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `employee_id` int(11) NOT NULL,
  `date` date NOT NULL,
  `status` varchar(255) NOT NULL,
  `clock_in` time NOT NULL,
  `clock_out` time NOT NULL,
  `late` time NOT NULL,
  `late_mark` tinyint(1) NOT NULL DEFAULT 0,
  `early_leaving` time NOT NULL,
  `early_mark` tinyint(1) NOT NULL DEFAULT 0,
  `overtime` time NOT NULL,
  `less_hours_mark` tinyint(1) NOT NULL DEFAULT 0,
  `total_rest` time NOT NULL,
  `deduction_units` decimal(3,1) NOT NULL DEFAULT 0.0,
  `created_by` int(11) NOT NULL,
  `device_type` varchar(255) DEFAULT NULL,
  `latitude` varchar(255) DEFAULT NULL,
  `longitude` varchar(255) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `photo` varchar(255) DEFAULT NULL,
  `photo_verified` tinyint(1) DEFAULT NULL,
  `device_type_out` varchar(255) DEFAULT NULL,
  `latitude_out` varchar(255) DEFAULT NULL,
  `longitude_out` varchar(255) DEFAULT NULL,
  `address_out` text DEFAULT NULL,
  `photo_out` varchar(255) DEFAULT NULL,
  `photo_out_verified` tinyint(1) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `facial_verification_photo` varchar(255) DEFAULT NULL,
  `facial_verification_status` enum('pending','passed','failed') NOT NULL DEFAULT 'pending',
  `facial_verification_confidence` decimal(5,2) NOT NULL DEFAULT 0.00,
  `professional_days_at_attendance` int(11) NOT NULL DEFAULT 0 COMMENT 'Days employed at time of attendance',
  `professional_months_at_attendance` int(11) NOT NULL DEFAULT 0 COMMENT 'Months employed at time of attendance',
  `professional_years_at_attendance` int(11) NOT NULL DEFAULT 0 COMMENT 'Years employed at time of attendance',
  `in_probation_at_attendance` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Was employee in probation at time of attendance',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2317 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

