   \r\n            <p>UNTUK PERHATIAN</p>\r\n            \r\n            <p>{date}</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>Jangka Waktu Layanan {duration} di {app_name}.</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>{payroll}</p>\r\n            \r\n            <p>Peran dan Tanggung Jawab</p>\r\n            \r\n            \r\n            \r\n            <p>Deskripsi singkat tentang pekerjaan karyawan dan pernyataan positif dari manajer atau supervisor.</p>\r\n            \r\n            \r\n            \r\n            <p>Sungguh-sungguh,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Tanda tangan</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(76,'it','<h3 style=\"text-align: center;\">Lettera di esperienza</h3>\r\n            \r\n            \r\n            \r\n            <p>{app_name}</p>\r\n            \r\n            <p>PER CHI &Egrave; COINVOLTO</p>\r\n            \r\n            <p>{date}</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>Durata del servizio {duration} in {app_name}.</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>{payroll}</p>\r\n            \r\n            <p>Ruoli e responsabilit&agrave;</p>\r\n            \r\n            \r\n            \r\n            <p>Breve descrizione del percorso lavorativo del dipendente e dichiarazione positiva del manager o supervisore.</p>\r\n            \r\n            \r\n            \r\n            <p>Cordiali saluti,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Firma</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(77,'ja','\r\n            <h3 style=\"text-align: center;\">体験談</h3>\r\n            \r\n            \r\n            \r\n            <p>{app_name}</p>\r\n            \r\n            <p>ご担当者様</p>\r\n            \r\n            <p>{date}</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{app_name} のサービス {duration} の保有期間。</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>{payroll}</p>\r\n            \r\n            <p>役割と責任</p>\r\n            \r\n            \r\n            \r\n            <p>従業員の雇用コースの簡単な説明と、マネージャーまたはスーパーバイザーからの肯定的な声明。</p>\r\n            \r\n            \r\n            \r\n            <p>心から、</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>サイン</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(78,'nl','<h3 style=\"text-align: center;\">Ervaringsbrief</h3>\r\n            \r\n            \r\n            <p>{app_name}</p>\r\n            \r\n            <p>VOOR WIE HET AANGAAT</p>\r\n            \r\n            <p>{date}</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>Diensttijd {duration} in {app_name}.</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>{payroll}</p>\r\n            \r\n            <p>Rollen en verantwoordelijkheden</p>\r\n            \r\n            \r\n            \r\n            <p>Korte omschrijving van het dienstverband van de medewerker en een positieve verklaring van de leidinggevende of leidinggevende.</p>\r\n            \r\n            \r\n            \r\n            <p>Eerlijk,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Handtekening</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(79,'pl','<h3 style=\"text-align: center;\">Doświadczenie List</h3>\r\n            \r\n            \r\n            \r\n            <p>{app_name}</p>\r\n            \r\n            <p>DO TYCH KT&Oacute;RYCH MOŻE TO DOTYCZYĆ</p>\r\n            \r\n            <p>{date}</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>Okres świadczenia usług {duration} w aplikacji {app_name}.</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>{payroll}</p>\r\n            \r\n            <p>Role i obowiązki</p>\r\n            \r\n            \r\n            \r\n            <p>Kr&oacute;tki opis przebiegu zatrudnienia pracownika oraz pozytywna opinia kierownika lub przełożonego.</p>\r\n            \r\n            \r\n            \r\n            <p>Z poważaniem,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Podpis</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(80,'pt','<h3 style=\"text-align: center;\">Carta de Experi&ecirc;ncia</h3>\r\n            \r\n            <p>{app_name}</p>\r\n            \r\n            <p>A QUEM POSSA INTERESSAR</p>\r\n            \r\n            <p>{date}</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>Tempo de servi&ccedil;o {duration} em {app_name}.</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>{payroll}</p>\r\n            \r\n            <p>Pap&eacute;is e responsabilidades</p>\r\n            \r\n            <p>Breve descri&ccedil;&atilde;o do curso de emprego do funcion&aacute;rio e uma declara&ccedil;&atilde;o positiva do gerente ou supervisor.</p>\r\n            \r\n            <p>Sinceramente,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Assinatura</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(81,'ru','<h3 style=\"text-align: center;\">Письмо об опыте</h3>\r\n            \r\n            \r\n            \r\n            <p>{app_name}</p>\r\n            \r\n            <p>ДЛЯ ПРЕДЪЯВЛЕНИЯ ПО МЕСТУ ТРЕБОВАНИЯ</p>\r\n            \r\n            <p>{date}</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>Срок службы {duration} в {app_name}.</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>{payroll}</p>\r\n            \r\n            <p>Роли и обязанности</p>\r\n            \r\n            \r\n            \r\n            <p>Краткое описание трудового стажа работника и положительное заключение руководителя или руководителя.</p>\r\n            \r\n            \r\n            \r\n            <p>Искренне,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Подпись</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(82,'tr','<h3 style=\"text-align: center;\">Tecrübe mektubu</h3>\r\n            \r\n            <p>{app_name}</p>\r\n            \r\n            <p>İLGİLİ MAKAMA</p>\r\n            \r\n            <p>{date}</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>Hizmet süresi {duration} içinde {app_name}.</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>{payroll}</p>\r\n            \r\n            <p>Görev ve Sorumluluklar</p>\r\n            \r\n            <p>Çalışanların istihdam sürecinin kısa açıklaması ve yönetici veya amirden olumlu bir açıklama.</p>\r\n            \r\n            <p>Samimi olarak,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>İmza</p>\r\