INSERT INTO `noc_certificates` VALUES (1,'ar','<h3 style=\"text-align: center;\">شهادة عدم ممانعة</h3>\n            \n            \n            \n            <p>التاريخ: {date}</p>\n            \n            \n            \n            <p>إلى من يهمه الأمر</p>\n            \n            \n            \n            <p>هذه الشهادة مخصصة للمطالبة بشهادة عدم ممانعة (NoC) للسيدة / السيد {employee_name} إذا انضمت إلى أي مؤسسة أخرى وقدمت خدماتها / خدماتها. يتم إبلاغه لأنه قام بتصفية جميع أرصدته واستلام أمانه من شركة {app_name}.</p>\n            \n            \n            \n            <p>نتمنى لها / لها التوفيق في المستقبل.</p>\n            \n            \n            \n            <p>بإخلاص،</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>التوقيع</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(2,'da','<h3 style=\"text-align: center;\">Ingen indsigelsesattest</h3>\n            \n            \n            \n            <p>Dato: {date}</p>\n            \n            \n            \n            <p>Til hvem det m&aring;tte vedr&oslash;re</p>\n            \n            \n            \n            <p>Dette certifikat er for at g&oslash;re krav p&aring; et No Objection Certificate (NoC) for Ms. / Mr. {employee_name}, hvis hun/han tilslutter sig og leverer sine tjenester til enhver anden organisation. Det informeres, da hun/han har udlignet alle sine saldi og modtaget sin sikkerhed fra {app_name}-virksomheden.</p>\n            \n            \n            \n            <p>Vi &oslash;nsker hende/ham held og lykke i fremtiden.</p>\n            \n            \n            \n            <p>Med venlig hilsen</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Underskrift</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(3,'de','<h3 style=\"text-align: center;\">Kein Einwand-Zertifikat</h3>\n            \n            \n            \n            <p>Datum {date}</p>\n            \n            \n            \n            <p>Wen auch immer es betrifft</p>\n            \n            \n            \n            <p>Dieses Zertifikat soll ein Unbedenklichkeitszertifikat (NoC) f&uuml;r Frau / Herrn {employee_name} beanspruchen, wenn sie/er einer anderen Organisation beitritt und ihre/seine Dienste anbietet. Sie wird informiert, da sie/er alle ihre/seine Guthaben ausgeglichen und ihre/seine Sicherheit von der Firma {app_name} erhalten hat.</p>\n            \n            \n            \n            <p>Wir w&uuml;nschen ihr/ihm viel Gl&uuml;ck f&uuml;r die Zukunft.</p>\n            \n            \n            \n            <p>Aufrichtig,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Unterschrift</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(4,'en','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>No Objection Certificate</strong></span></p>\n            \n            <p>Date: {date}</p>\n            \n            <p>To Whomsoever It May Concern</p>\n            \n            <p>This certificate is to claim a No Objection Certificate (NoC) for Ms. / Mr. {employee_name} if she/he joins and provides her/his services to any other organization. It is informed as she/he has cleared all her/his balances and received her/his security from {app_name} Company.</p>\n            \n            <p>We wish her/him good luck in the future.</p>\n            \n            <p>Sincerely,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>Signature</p>\n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(5,'es','<h3 style=\"text-align: center;\">Certificado de conformidad</h3>\n            \n            \n            \n            <p>Fecha: {date}</p>\n            \n            \n            \n            <p>A quien corresponda</p>\n            \n            \n            \n            <p>Este certificado es para reclamar un Certificado de No Objeci&oacute;n (NoC) para la Sra. / Sr. {employee_name} si ella / &eacute;l se une y brinda sus servicios a cualquier otra organizaci&oacute;n. Se informa que &eacute;l/ella ha liquidado todos sus saldos y recibido su seguridad de {app_name} Company.</p>\n            \n            \n            \n            <p>Le deseamos buena suerte en el futuro.</p>\n            \n            \n            \n            <p>Sinceramente,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Firma</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(6,'fr','<h3 style=\"text-align: center;\">Aucun certificat dopposition</h3>\n            \n            \n            <p>Date : {date}</p>\n            \n            \n            <p>&Agrave; toute personne concern&eacute;e</p>\n            \n            \n            <p>Ce certificat sert &agrave; r&eacute;clamer un certificat de non-objection (NoC) pour Mme / M. {employee_name} sil rejoint et fournit ses services &agrave; toute autre organisation. Il est inform&eacute; quil a sold&eacute; tous ses soldes et re&ccedil;u sa garantie de la part de la soci&eacute;t&eacute; {app_name}.</p>\n            \n            \n            <p>Nous lui souhaitons bonne chance pour lavenir.</p>\n            \n            \n            <p>Sinc&egrave;rement,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Signature</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(7,'id','<h3 style=\"text-align: center;\">Sertifikat Tidak Keberatan</h3>\n            \n            \n            \n            <p>Tanggal: {date}</p>\n            \n            \n            \n            <p>Kepada Siapa Pun Yang Memprihatinkan</p>\n            \n            \n            \n            <p>Sertifikat ini untuk mengklaim No Objection Certificate (NoC) untuk Ibu / Bapak {employee_name} jika dia bergabung dan memberikan layanannya ke organisasi lain mana pun. Diberitahukan karena dia telah melunasi semua saldonya dan menerima jaminannya dari Perusahaan {app_name}.</p>\n            \n            \n            \n            <p>Kami berharap dia sukses di masa depan.</p>\n            \n            \n            \n            <p>Sungguh-sungguh,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Tanda tangan</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(8,'it','<h3 style=\"text-align: center;\">Certificato di nulla osta</h3>\n            \n            \n            \n            <p>Data: {date}</p>\n            \n            \n            \n            <p>A chi pu&ograve; interessare</p>\n            \n            \n            \n            <p>Questo certificato serve a richiedere un certificato di non obiezione (NoC) per la signora / il signor {employee_name} se si unisce e fornisce i suoi servizi a qualsiasi altra organizzazione. Viene informato in quanto ha liquidato tutti i suoi saldi e ricevuto la sua sicurezza dalla societ&agrave; {app_name}.</p>\n            \n            \n            \n            <p>Le auguriamo buona fortuna per il futuro.</p>\n            \n            \n            \n            <p>Cordiali saluti,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Firma</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(9,'ja','<h3 style=\"text-align: center;\">異議なし証明書</h3>\n            \n            \n            \n            <p>日付: {date}</p>\n            \n            \n            \n            <p>関係者各位</p>\n            \n            \n            \n            <p>この証明書は、Ms. / Mr. {employee_name} が他の組織に参加してサービスを提供する場合に、異議なし証明書 (NoC) を請求するためのものです。彼女/彼/彼がすべての残高を清算し、{app_name} 会社から彼女/彼のセキュリティを受け取ったことが通知されます。</p>\n            \n            \n            \n            <p>彼女/彼の今後の幸運を祈っています。</p>\n            \n            \n            \n            <p>心から、</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>サイン</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(10,'nl','<h3 style=\"text-align: center;\">Geen bezwaarcertificaat</h3>\n            \n            \n            \n            <p>Datum: {date}</p>\n            \n            \n            \n            <p>Aan wie het ook aangaat</p>\n            \n            \n            \n            <p>Dit certificaat is bedoeld om aanspraak te maken op een Geen Bezwaarcertificaat (NoC) voor mevrouw/dhr. {employee_name} als zij/hij lid wordt en haar/zijn diensten verleent aan een andere organisatie. Het wordt ge&iuml;nformeerd als zij/hij al haar/zijn saldos heeft gewist en haar/zijn zekerheid heeft ontvangen van {app_name} Company.</p>\n            \n            \n            \n            <p>We wensen haar/hem veel succes in de toekomst.</p>\n            \n            \n            \n            <p>Eerlijk,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Handtekening</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(11,'pl','<h3 style=\"text-align: center;\">Certyfikat braku sprzeciwu</h3>\n            \n            \n            \n            <p>Data: {date}</p>\n            \n            \n            \n            <p>Do kogo to może dotyczyć</p>\n            \n            \n            \n            <p>Ten certyfikat służy do ubiegania się o Certyfikat No Objection Certificate (NoC) dla Pani/Pana {employee_name}, jeśli ona/ona dołącza i świadczy swoje usługi na rzecz jakiejkolwiek innej organizacji. Jest o tym informowany, ponieważ wyczyścił wszystkie swoje salda i otrzymał swoje zabezpieczenie od firmy {app_name}.</p>\n            \n            \n            \n            <p>Życzymy jej/jej powodzenia w przyszłości.</p>\n            \n            \n            \n            <p>Z poważaniem,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Podpis</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(12,'pt','<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\n            \n            \n            \n            <p>Data: {date}</p>\n            \n            \n            \n            <p>A quem interessar</p>\n            \n            \n            \n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\n            \n            \n            \n            <p>Desejamos-lhe boa sorte no futuro.</p>\n            \n            \n            \n            <p>Sinceramente,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Assinatura</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(13,'ru','<h3 style=\"text-align: center;\">Сертификат об отсутствии возражений</h3>\n            \n            \n            \n            <p>Дата: {date}</p>\n            \n            \n            \n            <p>Кого бы это ни касалось</p>\n            \n            \n            \n            <p>Этот сертификат предназначен для получения Сертификата об отсутствии возражений (NoC) для г-жи / г-на {employee_name}, если она / он присоединяется и предоставляет свои услуги любой другой организации. Сообщается, что она/он очистила все свои балансы и получила свою безопасность от компании {app_name}.</p>\n            \n            \n            \n            <p>Мы желаем ей/ему удачи в будущем.</p>\n            \n            \n            \n            <p>Искренне,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Подпись</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(14,'tr','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>İtiraz Yok Belgesi</strong></span></p>\n            \n            <p>Tarih: {date}</p>\n            \n            <p>İlgilenebilecek Kişiye</p>\n            \n            <p>Bu sertifika, Bayan / Bay için bir İtiraz Yok Sertifikası (NoC) talep etmek içindir {employee_name} başka bir kuruluşa katılır ve hizmet verirse. Tüm bakiyelerini kapattığı ve teminatını aldığı bilgisi verilir {app_name} Şirket.</p>\n            \n            <p>Kendisine gelecekte iyi şanslar diliyoruz.</p>\n            \n            <p>Samimi olarak,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>İmza</p>\n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(15,'zh','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>无异议证书</strong></span></p>\n            \n            <p>日期: {date}</p>\n            \n            <p>致相关负责人</p>\n            \n            <p>此证书旨在为女士/先生申请无异议证书（NoC）。{employee_name} 如果她/他加入任何其他组织并向其提供服务。据了解，她/他已结清所有余额并从以下机构收到她/他的担保： {app_name} 公司.</p>\n            \n            <p>我们祝她/他未来好运.</p>\n            \n            <p>真挚地,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>签名</p>\n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(16,'he','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>אין תעודת התנגדות</strong></span></p>\n            \n            <p>תַאֲרִיך: {date}</p>\n            \n            <p>לכל מאן דבעי</p>\n            \n            <p>תעודה זו מיועדת לתבוע אישור ללא התנגדות (NoC) עבור גב / מר. {employee_name} אם הוא/ה מצטרף ומספק את שירותיו/ה לכל ארגון אחר. זה מודיע כפי שהיא / הוא פינה את כל היתרות שלה / שלו וקיבל את האבטחה שלה / שלו {app_name} חֶברָה.</p>\n            \n            <p>אנו מאחלים לו/לה בהצלחה בעתיד.</p>\n            \n            <p>בכנות,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>חֲתִימָה</p>\n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(17,'pt-br','<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\n                    \n            <p>Data: {date}</p>\n            \n            <p>A quem interessar</p>\n            \n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\n            \n            <p>Desejamos-lhe boa sorte no futuro.</p>\n            \n            <p>Sinceramente,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Assinatura</p>\n            \n            <p>{app_name}</p>',2,'2026-02-05 05:36:41','2026-02-05 05:36:41'),(18,'ar','<h3 style=\"text-align: center;\">شهادة عدم ممانعة</h3>\n            \n            \n            \n            <p>التاريخ: {date}</p>\n            \n            \n            \n            <p>إلى من يهمه الأمر</p>\n            \n            \n            \n            <p>هذه الشهادة مخصصة للمطالبة بشهادة عدم ممانعة (NoC) للسيدة / السيد {employee_name} إذا انضمت إلى أي مؤسسة أخرى وقدمت خدماتها / خدماتها. يتم إبلاغه لأنه قام بتصفية جميع أرصدته واستلام أمانه من شركة {app_name}.</p>\n            \n            \n            \n            <p>نتمنى لها / لها التوفيق في المستقبل.</p>\n            \n            \n            \n            <p>بإخلاص،</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>التوقيع</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(19,'da','<h3 style=\"text-align: center;\">Ingen indsigelsesattest</h3>\n            \n            \n            \n            <p>Dato: {date}</p>\n            \n            \n            \n            <p>Til hvem det m&aring;tte vedr&oslash;re</p>\n            \n            \n            \n            <p>Dette certifikat er for at g&oslash;re krav p&aring; et No Objection Certificate (NoC) for Ms. / Mr. {employee_name}, hvis hun/han tilslutter sig og leverer sine tjenester til enhver anden organisation. Det informeres, da hun/han har udlignet alle sine saldi og modtaget sin sikkerhed fra {app_name}-virksomheden.</p>\n            \n            \n            \n            <p>Vi &oslash;nsker hende/ham held og lykke i fremtiden.</p>\n            \n            \n            \n            <p>Med venlig hilsen</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Underskrift</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(20,'de','<h3 style=\"text-align: center;\">Kein Einwand-Zertifikat</h3>\n            \n            \n            \n            <p>Datum {date}</p>\n            \n            \n            \n            <p>Wen auch immer es betrifft</p>\n            \n            \n            \n            <p>Dieses Zertifikat soll ein Unbedenklichkeitszertifikat (NoC) f&uuml;r Frau / Herrn {employee_name} beanspruchen, wenn sie/er einer anderen Organisation beitritt und ihre/seine Dienste anbietet. Sie wird informiert, da sie/er alle ihre/seine Guthaben ausgeglichen und ihre/seine Sicherheit von der Firma {app_name} erhalten hat.</p>\n            \n            \n            \n            <p>Wir w&uuml;nschen ihr/ihm viel Gl&uuml;ck f&uuml;r die Zukunft.</p>\n            \n            \n            \n            <p>Aufrichtig,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Unterschrift</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(21,'en','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>No Objection Certificate</strong></span></p>\n            \n            <p>Date: {date}</p>\n            \n            <p>To Whomsoever It May Concern</p>\n            \n            <p>This certificate is to claim a No Objection Certificate (NoC) for Ms. / Mr. {employee_name} if she/he joins and provides her/his services to any other organization. It is informed as she/he has cleared all her/his balances and received her/his security from {app_name} Company.</p>\n            \n            <p>We wish her/him good luck in the future.</p>\n            \n            <p>Sincerely,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>Signature</p>\n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(22,'es','<h3 style=\"text-align: center;\">Certificado de conformidad</h3>\n            \n            \n            \n            <p>Fecha: {date}</p>\n            \n            \n            \n            <p>A quien corresponda</p>\n            \n            \n            \n            <p>Este certificado es para reclamar un Certificado de No Objeci&oacute;n (NoC) para la Sra. / Sr. {employee_name} si ella / &eacute;l se une y brinda sus servicios a cualquier otra organizaci&oacute;n. Se informa que &eacute;l/ella ha liquidado todos sus saldos y recibido su seguridad de {app_name} Company.</p>\n            \n            \n            \n            <p>Le deseamos buena suerte en el futuro.</p>\n            \n            \n            \n            <p>Sinceramente,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Firma</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(23,'fr','<h3 style=\"text-align: center;\">Aucun certificat dopposition</h3>\n            \n            \n            <p>Date : {date}</p>\n            \n            \n            <p>&Agrave; toute personne concern&eacute;e</p>\n            \n            \n            <p>Ce certificat sert &agrave; r&eacute;clamer un certificat de non-objection (NoC) pour Mme / M. {employee_name} sil rejoint et fournit ses services &agrave; toute autre organisation. Il est inform&eacute; quil a sold&eacute; tous ses soldes et re&ccedil;u sa garantie de la part de la soci&eacute;t&eacute; {app_name}.</p>\n            \n            \n            <p>Nous lui souhaitons bonne chance pour lavenir.</p>\n            \n            \n            <p>Sinc&egrave;rement,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Signature</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(24,'id','<h3 style=\"text-align: center;\">Sertifikat Tidak Keberatan</h3>\n            \n            \n            \n            <p>Tanggal: {date}</p>\n            \n            \n            \n            <p>Kepada Siapa Pun Yang Memprihatinkan</p>\n            \n            \n            \n            <p>Sertifikat ini untuk mengklaim No Objection Certificate (NoC) untuk Ibu / Bapak {employee_name} jika dia bergabung dan memberikan layanannya ke organisasi lain mana pun. Diberitahukan karena dia telah melunasi semua saldonya dan menerima jaminannya dari Perusahaan {app_name}.</p>\n            \n            \n            \n            <p>Kami berharap dia sukses di masa depan.</p>\n            \n            \n            \n            <p>Sungguh-sungguh,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Tanda tangan</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(25,'it','<h3 style=\"text-align: center;\">Certificato di nulla osta</h3>\n            \n            \n            \n            <p>Data: {date}</p>\n            \n            \n            \n            <p>A chi pu&ograve; interessare</p>\n            \n            \n            \n            <p>Questo certificato serve a richiedere un certificato di non obiezione (NoC) per la signora / il signor {employee_name} se si unisce e fornisce i suoi servizi a qualsiasi altra organizzazione. Viene informato in quanto ha liquidato tutti i suoi saldi e ricevuto la sua sicurezza dalla societ&agrave; {app_name}.</p>\n            \n            \n            \n            <p>Le auguriamo buona fortuna per il futuro.</p>\n            \n            \n            \n            <p>Cordiali saluti,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Firma</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(26,'ja','<h3 style=\"text-align: center;\">異議なし証明書</h3>\n            \n            \n            \n            <p>日付: {date}</p>\n            \n            \n            \n            <p>関係者各位</p>\n            \n            \n            \n            <p>この証明書は、Ms. / Mr. {employee_name} が他の組織に参加してサービスを提供する場合に、異議なし証明書 (NoC) を請求するためのものです。彼女/彼/彼がすべての残高を清算し、{app_name} 会社から彼女/彼のセキュリティを受け取ったことが通知されます。</p>\n            \n            \n            \n            <p>彼女/彼の今後の幸運を祈っています。</p>\n            \n            \n            \n            <p>心から、</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>サイン</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(27,'nl','<h3 style=\"text-align: center;\">Geen bezwaarcertificaat</h3>\n            \n            \n            \n            <p>Datum: {date}</p>\n            \n            \n            \n            <p>Aan wie het ook aangaat</p>\n            \n            \n            \n            <p>Dit certificaat is bedoeld om aanspraak te maken op een Geen Bezwaarcertificaat (NoC) voor mevrouw/dhr. {employee_name} als zij/hij lid wordt en haar/zijn diensten verleent aan een andere organisatie. Het wordt ge&iuml;nformeerd als zij/hij al haar/zijn saldos heeft gewist en haar/zijn zekerheid heeft ontvangen van {app_name} Company.</p>\n            \n            \n            \n            <p>We wensen haar/hem veel succes in de toekomst.</p>\n            \n            \n            \n            <p>Eerlijk,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Handtekening</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(28,'pl','<h3 style=\"text-align: center;\">Certyfikat braku sprzeciwu</h3>\n            \n            \n            \n            <p>Data: {date}</p>\n            \n            \n            \n            <p>Do kogo to może dotyczyć</p>\n            \n            \n            \n            <p>Ten certyfikat służy do ubiegania się o Certyfikat No Objection Certificate (NoC) dla Pani/Pana {employee_name}, jeśli ona/ona dołącza i świadczy swoje usługi na rzecz jakiejkolwiek innej organizacji. Jest o tym informowany, ponieważ wyczyścił wszystkie swoje salda i otrzymał swoje zabezpieczenie od firmy {app_name}.</p>\n            \n            \n            \n            <p>Życzymy jej/jej powodzenia w przyszłości.</p>\n            \n            \n            \n            <p>Z poważaniem,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Podpis</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(29,'pt','<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\n                    \n            <p>Data: {date}</p>\n            \n            <p>A quem interessar</p>\n            \n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\n            \n            <p>Desejamos-lhe boa sorte no futuro.</p>\n            \n            <p>Sinceramente,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Assinatura</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(30,'ru','<h3 style=\"text-align: center;\">Сертификат об отсутствии возражений</h3>\n            \n            \n            \n            <p>Дата: {date}</p>\n            \n            \n            \n            <p>Кого бы это ни касалось</p>\n            \n            \n            \n            <p>Этот сертификат предназначен для получения Сертификата об отсутствии возражений (NoC) для г-жи / г-на {employee_name}, если она / он присоединяется и предоставляет свои услуги любой другой организации. Сообщается, что она/он очистила все свои балансы и получила свою безопасность от компании {app_name}.</p>\n            \n            \n            \n            <p>Мы желаем ей/ему удачи в будущем.</p>\n            \n            \n            \n            <p>Искренне,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Подпись</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(31,'tr','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>İtiraz Yok Belgesi</strong></span></p>\n            \n            <p>Tarih: {date}</p>\n            \n            <p>İlgilenebilecek Kişiye</p>\n            \n            <p>Bu sertifika, Bayan / Bay için bir İtiraz Yok Sertifikası (NoC) talep etmek içindir {employee_name} başka bir kuruluşa katılır ve hizmet verirse. Tüm bakiyelerini kapattığı ve teminatını aldığı bilgisi verilir {app_name} Şirket.</p>\n            \n            <p>Kendisine gelecekte iyi şanslar diliyoruz.</p>\n            \n            <p>Samimi olarak,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>İmza</p>\n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(32,'zh','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>无异议证书</strong></span></p>\n            \n            <p>日期: {date}</p>\n            \n            <p>致相关负责人</p>\n            \n            <p>此证书旨在为女士/先生申请无异议证书（NoC）。{employee_name} 如果她/他加入任何其他组织并向其提供服务。据了解，她/他已结清所有余额并从以下机构收到她/他的担保： {app_name} 公司.</p>\n            \n            <p>我们祝她/他未来好运.</p>\n            \n            <p>真挚地,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>签名</p>\n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(33,'he','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>אין תעודת התנגדות</strong></span></p>\n            \n            <p>תַאֲרִיך: {date}</p>\n            \n            <p>לכל מאן דבעי</p>\n            \n            <p>תעודה זו מיועדת לתבוע אישור ללא התנגדות (NoC) עבור גב / מר. {employee_name} אם הוא/ה מצטרף ומספק את שירותיו/ה לכל ארגון אחר. זה מודיע כפי שהיא / הוא פינה את כל היתרות שלה / שלו וקיבל את האבטחה שלה / שלו {app_name} חֶברָה.</p>\n            \n            <p>אנו מאחלים לו/לה בהצלחה בעתיד.</p>\n            \n            <p>בכנות,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>חֲתִימָה</p>\n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(34,'pt-br','<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\n                    \n            <p>Data: {date}</p>\n            \n            <p>A quem interessar</p>\n            \n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\n            \n            <p>Desejamos-lhe boa sorte no futuro.</p>\n            \n            <p>Sinceramente,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Assinatura</p>\n            \n            <p>{app_name}</p>',4,'2026-02-05 05:39:26','2026-02-05 05:39:26'),(35,'ar','<h3 style=\"text-align: center;\">شهادة عدم ممانعة</h3>\n            \n            \n            \n            <p>التاريخ: {date}</p>\n            \n            \n            \n            <p>إلى من يهمه الأمر</p>\n            \n            \n            \n            <p>هذه الشهادة مخصصة للمطالبة بشهادة عدم ممانعة (NoC) للسيدة / السيد {employee_name} إذا انضمت إلى أي مؤسسة أخرى وقدمت خدماتها / خدماتها. يتم إبلاغه لأنه قام بتصفية جميع أرصدته واستلام أمانه من شركة {app_name}.</p>\n            \n            \n            \n            <p>نتمنى لها / لها التوفيق في المستقبل.</p>\n            \n            \n            \n            <p>بإخلاص،</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>التوقيع</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(36,'da','<h3 style=\"text-align: center;\">Ingen indsigelsesattest</h3>\n            \n            \n            \n            <p>Dato: {date}</p>\n            \n            \n            \n            <p>Til hvem det m&aring;tte vedr&oslash;re</p>\n            \n            \n            \n            <p>Dette certifikat er for at g&oslash;re krav p&aring; et No Objection Certificate (NoC) for Ms. / Mr. {employee_name}, hvis hun/han tilslutter sig og leverer sine tjenester til enhver anden organisation. Det informeres, da hun/han har udlignet alle sine saldi og modtaget sin sikkerhed fra {app_name}-virksomheden.</p>\n            \n            \n            \n            <p>Vi &oslash;nsker hende/ham held og lykke i fremtiden.</p>\n            \n            \n            \n            <p>Med venlig hilsen</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Underskrift</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(37,'de','<h3 style=\"text-align: center;\">Kein Einwand-Zertifikat</h3>\n            \n            \n            \n            <p>Datum {date}</p>\n            \n            \n            \n            <p>Wen auch immer es betrifft</p>\n            \n            \n            \n            <p>Dieses Zertifikat soll ein Unbedenklichkeitszertifikat (NoC) f&uuml;r Frau / Herrn {employee_name} beanspruchen, wenn sie/er einer anderen Organisation beitritt und ihre/seine Dienste anbietet. Sie wird informiert, da sie/er alle ihre/seine Guthaben ausgeglichen und ihre/seine Sicherheit von der Firma {app_name} erhalten hat.</p>\n            \n            \n            \n            <p>Wir w&uuml;nschen ihr/ihm viel Gl&uuml;ck f&uuml;r die Zukunft.</p>\n            \n            \n            \n            <p>Aufrichtig,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Unterschrift</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(38,'en','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>No Objection Certificate</strong></span></p>\n            \n            <p>Date: {date}</p>\n            \n            <p>To Whomsoever It May Concern</p>\n            \n            <p>This certificate is to claim a No Objection Certificate (NoC) for Ms. / Mr. {employee_name} if she/he joins and provides her/his services to any other organization. It is informed as she/he has cleared all her/his balances and received her/his security from {app_name} Company.</p>\n            \n            <p>We wish her/him good luck in the future.</p>\n            \n            <p>Sincerely,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>Signature</p>\n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(39,'es','<h3 style=\"text-align: center;\">Certificado de conformidad</h3>\n            \n            \n            \n            <p>Fecha: {date}</p>\n            \n            \n            \n            <p>A quien corresponda</p>\n            \n            \n            \n            <p>Este certificado es para reclamar un Certificado de No Objeci&oacute;n (NoC) para la Sra. / Sr. {employee_name} si ella / &eacute;l se une y brinda sus servicios a cualquier otra organizaci&oacute;n. Se informa que &eacute;l/ella ha liquidado todos sus saldos y recibido su seguridad de {app_name} Company.</p>\n            \n            \n            \n            <p>Le deseamos buena suerte en el futuro.</p>\n            \n            \n            \n            <p>Sinceramente,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Firma</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(40,'fr','<h3 style=\"text-align: center;\">Aucun certificat dopposition</h3>\n            \n            \n            <p>Date : {date}</p>\n            \n            \n            <p>&Agrave; toute personne concern&eacute;e</p>\n            \n            \n            <p>Ce certificat sert &agrave; r&eacute;clamer un certificat de non-objection (NoC) pour Mme / M. {employee_name} sil rejoint et fournit ses services &agrave; toute autre organisation. Il est inform&eacute; quil a sold&eacute; tous ses soldes et re&ccedil;u sa garantie de la part de la soci&eacute;t&eacute; {app_name}.</p>\n            \n            \n            <p>Nous lui souhaitons bonne chance pour lavenir.</p>\n            \n            \n            <p>Sinc&egrave;rement,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Signature</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(41,'id','<h3 style=\"text-align: center;\">Sertifikat Tidak Keberatan</h3>\n            \n            \n            \n            <p>Tanggal: {date}</p>\n            \n            \n            \n            <p>Kepada Siapa Pun Yang Memprihatinkan</p>\n            \n            \n            \n            <p>Sertifikat ini untuk mengklaim No Objection Certificate (NoC) untuk Ibu / Bapak {employee_name} jika dia bergabung dan memberikan layanannya ke organisasi lain mana pun. Diberitahukan karena dia telah melunasi semua saldonya dan menerima jaminannya dari Perusahaan {app_name}.</p>\n            \n            \n            \n            <p>Kami berharap dia sukses di masa depan.</p>\n            \n            \n            \n            <p>Sungguh-sungguh,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Tanda tangan</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(42,'it','<h3 style=\"text-align: center;\">Certificato di nulla osta</h3>\n            \n            \n            \n            <p>Data: {date}</p>\n            \n            \n            \n            <p>A chi pu&ograve; interessare</p>\n            \n            \n            \n            <p>Questo certificato serve a richiedere un certificato di non obiezione (NoC) per la signora / il signor {employee_name} se si unisce e fornisce i suoi servizi a qualsiasi altra organizzazione. Viene informato in quanto ha liquidato tutti i suoi saldi e ricevuto la sua sicurezza dalla societ&agrave; {app_name}.</p>\n            \n            \n            \n            <p>Le auguriamo buona fortuna per il futuro.</p>\n            \n            \n            \n            <p>Cordiali saluti,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Firma</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(43,'ja','<h3 style=\"text-align: center;\">異議なし証明書</h3>\n            \n            \n            \n            <p>日付: {date}</p>\n            \n            \n            \n            <p>関係者各位</p>\n            \n            \n            \n            <p>この証明書は、Ms. / Mr. {employee_name} が他の組織に参加してサービスを提供する場合に、異議なし証明書 (NoC) を請求するためのものです。彼女/彼/彼がすべての残高を清算し、{app_name} 会社から彼女/彼のセキュリティを受け取ったことが通知されます。</p>\n            \n            \n            \n            <p>彼女/彼の今後の幸運を祈っています。</p>\n            \n            \n            \n            <p>心から、</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>サイン</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(44,'nl','<h3 style=\"text-align: center;\">Geen bezwaarcertificaat</h3>\n            \n            \n            \n            <p>Datum: {date}</p>\n            \n            \n            \n            <p>Aan wie het ook aangaat</p>\n            \n            \n            \n            <p>Dit certificaat is bedoeld om aanspraak te maken op een Geen Bezwaarcertificaat (NoC) voor mevrouw/dhr. {employee_name} als zij/hij lid wordt en haar/zijn diensten verleent aan een andere organisatie. Het wordt ge&iuml;nformeerd als zij/hij al haar/zijn saldos heeft gewist en haar/zijn zekerheid heeft ontvangen van {app_name} Company.</p>\n            \n            \n            \n            <p>We wensen haar/hem veel succes in de toekomst.</p>\n            \n            \n            \n            <p>Eerlijk,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Handtekening</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(45,'pl','<h3 style=\"text-align: center;\">Certyfikat braku sprzeciwu</h3>\n            \n            \n            \n            <p>Data: {date}</p>\n            \n            \n            \n            <p>Do kogo to może dotyczyć</p>\n            \n            \n            \n            <p>Ten certyfikat służy do ubiegania się o Certyfikat No Objection Certificate (NoC) dla Pani/Pana {employee_name}, jeśli ona/ona dołącza i świadczy swoje usługi na rzecz jakiejkolwiek innej organizacji. Jest o tym informowany, ponieważ wyczyścił wszystkie swoje salda i otrzymał swoje zabezpieczenie od firmy {app_name}.</p>\n            \n            \n            \n            <p>Życzymy jej/jej powodzenia w przyszłości.</p>\n            \n            \n            \n            <p>Z poważaniem,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Podpis</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(46,'pt','<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\n                    \n            <p>Data: {date}</p>\n            \n            <p>A quem interessar</p>\n            \n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\n            \n            <p>Desejamos-lhe boa sorte no futuro.</p>\n            \n            <p>Sinceramente,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Assinatura</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(47,'ru','<h3 style=\"text-align: center;\">Сертификат об отсутствии возражений</h3>\n            \n            \n            \n            <p>Дата: {date}</p>\n            \n            \n            \n            <p>Кого бы это ни касалось</p>\n            \n            \n            \n            <p>Этот сертификат предназначен для получения Сертификата об отсутствии возражений (NoC) для г-жи / г-на {employee_name}, если она / он присоединяется и предоставляет свои услуги любой другой организации. Сообщается, что она/он очистила все свои балансы и получила свою безопасность от компании {app_name}.</p>\n            \n            \n            \n            <p>Мы желаем ей/ему удачи в будущем.</p>\n            \n            \n            \n            <p>Искренне,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Подпись</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(48,'tr','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>İtiraz Yok Belgesi</strong></span></p>\n            \n            <p>Tarih: {date}</p>\n            \n            <p>İlgilenebilecek Kişiye</p>\n            \n            <p>Bu sertifika, Bayan / Bay için bir İtiraz Yok Sertifikası (NoC) talep etmek içindir {employee_name} başka bir kuruluşa katılır ve hizmet verirse. Tüm bakiyelerini kapattığı ve teminatını aldığı bilgisi verilir {app_name} Şirket.</p>\n            \n            <p>Kendisine gelecekte iyi şanslar diliyoruz.</p>\n            \n            <p>Samimi olarak,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>İmza</p>\n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(49,'zh','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>无异议证书</strong></span></p>\n            \n            <p>日期: {date}</p>\n            \n            <p>致相关负责人</p>\n            \n            <p>此证书旨在为女士/先生申请无异议证书（NoC）。{employee_name} 如果她/他加入任何其他组织并向其提供服务。据了解，她/他已结清所有余额并从以下机构收到她/他的担保： {app_name} 公司.</p>\n            \n            <p>我们祝她/他未来好运.</p>\n            \n            <p>真挚地,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>签名</p>\n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(50,'he','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>אין תעודת התנגדות</strong></span></p>\n            \n            <p>תַאֲרִיך: {date}</p>\n            \n            <p>לכל מאן דבעי</p>\n            \n            <p>תעודה זו מיועדת לתבוע אישור ללא התנגדות (NoC) עבור גב / מר. {employee_name} אם הוא/ה מצטרף ומספק את שירותיו/ה לכל ארגון אחר. זה מודיע כפי שהיא / הוא פינה את כל היתרות שלה / שלו וקיבל את האבטחה שלה / שלו {app_name} חֶברָה.</p>\n            \n            <p>אנו מאחלים לו/לה בהצלחה בעתיד.</p>\n            \n            <p>בכנות,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>חֲתִימָה</p>\n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(51,'pt-br','<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\n                    \n            <p>Data: {date}</p>\n            \n            <p>A quem interessar</p>\n            \n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\n            \n            <p>Desejamos-lhe boa sorte no futuro.</p>\n            \n            <p>Sinceramente,</p>\n            \n            <p>{employee_name}</p>\n            \n            <p>{designation}</p>\n            \n            <p>Assinatura</p>\n            \n            <p>{app_name}</p>',6,'2026-02-06 23:44:53','2026-02-06 23:44:53'),(52,'ar','<h3 style=\"text-align: center;\">شهادة عدم ممانعة</h3>\r\n            \r\n            \r\n            \r\n            <p>التاريخ: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>إلى من يهمه الأمر</p>\r\n            \r\n            \r\n            \r\n            <p>هذه الشهادة مخصصة للمطالبة بشهادة عدم ممانعة (NoC) للسيدة / السيد {employee_name} إذا انضمت إلى أي مؤسسة أخرى وقدمت خدماتها / خدماتها. يتم إبلاغه لأنه قام بتصفية جميع أرصدته واستلام أمانه من شركة {app_name}.</p>\r\n            \r\n            \r\n            \r\n            <p>نتمنى لها / لها التوفيق في المستقبل.</p>\r\n            \r\n            \r\n            \r\n            <p>بإخلاص،</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>التوقيع</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(53,'da','<h3 style=\"text-align: center;\">Ingen indsigelsesattest</h3>\r\n            \r\n            \r\n            \r\n            <p>Dato: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Til hvem det m&aring;tte vedr&oslash;re</p>\r\n            \r\n            \r\n            \r\n            <p>Dette certifikat er for at g&oslash;re krav p&aring; et No Objection Certificate (NoC) for Ms. / Mr. {employee_name}, hvis hun/han tilslutter sig og leverer sine tjenester til enhver anden organisation. Det informeres, da hun/han har udlignet alle sine saldi og modtaget sin sikkerhed fra {app_name}-virksomheden.</p>\r\n            \r\n            \r\n            \r\n            <p>Vi &oslash;nsker hende/ham held og lykke i fremtiden.</p>\r\n            \r\n            \r\n            \r\n            <p>Med venlig hilsen</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Underskrift</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(54,'de','<h3 style=\"text-align: center;\">Kein Einwand-Zertifikat</h3>\r\n            \r\n            \r\n            \r\n            <p>Datum {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Wen auch immer es betrifft</p>\r\n            \r\n            \r\n            \r\n            <p>Dieses Zertifikat soll ein Unbedenklichkeitszertifikat (NoC) f&uuml;r Frau / Herrn {employee_name} beanspruchen, wenn sie/er einer anderen Organisation beitritt und ihre/seine Dienste anbietet. Sie wird informiert, da sie/er alle ihre/seine Guthaben ausgeglichen und ihre/seine Sicherheit von der Firma {app_name} erhalten hat.</p>\r\n            \r\n            \r\n            \r\n            <p>Wir w&uuml;nschen ihr/ihm viel Gl&uuml;ck f&uuml;r die Zukunft.</p>\r\n            \r\n            \r\n            \r\n            <p>Aufrichtig,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Unterschrift</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(55,'en','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>No Objection Certificate</strong></span></p>\r\n            \r\n            <p>Date: {date}</p>\r\n            \r\n            <p>To Whomsoever It May Concern</p>\r\n            \r\n            <p>This certificate is to claim a No Objection Certificate (NoC) for Ms. / Mr. {employee_name} if she/he joins and provides her/his services to any other organization. It is informed as she/he has cleared all her/his balances and received her/his security from {app_name} Company.</p>\r\n            \r\n            <p>We wish her/him good luck in the future.</p>\r\n            \r\n            <p>Sincerely,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>Signature</p>\r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(56,'es','<h3 style=\"text-align: center;\">Certificado de conformidad</h3>\r\n            \r\n            \r\n            \r\n            <p>Fecha: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>A quien corresponda</p>\r\n            \r\n            \r\n            \r\n            <p>Este certificado es para reclamar un Certificado de No Objeci&oacute;n (NoC) para la Sra. / Sr. {employee_name} si ella / &eacute;l se une y brinda sus servicios a cualquier otra organizaci&oacute;n. Se informa que &eacute;l/ella ha liquidado todos sus saldos y recibido su seguridad de {app_name} Company.</p>\r\n            \r\n            \r\n            \r\n            <p>Le deseamos buena suerte en el futuro.</p>\r\n            \r\n            \r\n            \r\n            <p>Sinceramente,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Firma</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(57,'fr','<h3 style=\"text-align: center;\">Aucun certificat dopposition</h3>\r\n            \r\n            \r\n            <p>Date : {date}</p>\r\n            \r\n            \r\n            <p>&Agrave; toute personne concern&eacute;e</p>\r\n            \r\n            \r\n            <p>Ce certificat sert &agrave; r&eacute;clamer un certificat de non-objection (NoC) pour Mme / M. {employee_name} sil rejoint et fournit ses services &agrave; toute autre organisation. Il est inform&eacute; quil a sold&eacute; tous ses soldes et re&ccedil;u sa garantie de la part de la soci&eacute;t&eacute; {app_name}.</p>\r\n            \r\n            \r\n            <p>Nous lui souhaitons bonne chance pour lavenir.</p>\r\n            \r\n            \r\n            <p>Sinc&egrave;rement,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Signature</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(58,'id','<h3 style=\"text-align: center;\">Sertifikat Tidak Keberatan</h3>\r\n            \r\n            \r\n            \r\n            <p>Tanggal: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Kepada Siapa Pun Yang Memprihatinkan</p>\r\n            \r\n            \r\n            \r\n            <p>Sertifikat ini untuk mengklaim No Objection Certificate (NoC) untuk Ibu / Bapak {employee_name} jika dia bergabung dan memberikan layanannya ke organisasi lain mana pun. Diberitahukan karena dia telah melunasi semua saldonya dan menerima jaminannya dari Perusahaan {app_name}.</p>\r\n            \r\n            \r\n            \r\n            <p>Kami berharap dia sukses di masa depan.</p>\r\n            \r\n            \r\n            \r\n            <p>Sungguh-sungguh,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Tanda tangan</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(59,'it','<h3 style=\"text-align: center;\">Certificato di nulla osta</h3>\r\n            \r\n            \r\n            \r\n            <p>Data: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>A chi pu&ograve; interessare</p>\r\n            \r\n            \r\n            \r\n            <p>Questo certificato serve a richiedere un certificato di non obiezione (NoC) per la signora / il signor {employee_name} se si unisce e fornisce i suoi servizi a qualsiasi altra organizzazione. Viene informato in quanto ha liquidato tutti i suoi saldi e ricevuto la sua sicurezza dalla societ&agrave; {app_name}.</p>\r\n            \r\n            \r\n            \r\n            <p>Le auguriamo buona fortuna per il futuro.</p>\r\n            \r\n            \r\n            \r\n            <p>Cordiali saluti,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Firma</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(60,'ja','<h3 style=\"text-align: center;\">異議なし証明書</h3>\r\n            \r\n            \r\n            \r\n            <p>日付: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>関係者各位</p>\r\n            \r\n            \r\n            \r\n            <p>この証明書は、Ms. / Mr. {employee_name} が他の組織に参加してサービスを提供する場合に、異議なし証明書 (NoC) を請求するためのものです。彼女/彼/彼がすべての残高を清算し、{app_name} 会社から彼女/彼のセキュリティを受け取ったことが通知されます。</p>\r\n            \r\n            \r\n            \r\n            <p>彼女/彼の今後の幸運を祈っています。</p>\r\n            \r\n            \r\n            \r\n            <p>心から、</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>サイン</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(61,'nl','<h3 style=\"text-align: center;\">Geen bezwaarcertificaat</h3>\r\n            \r\n            \r\n            \r\n            <p>Datum: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Aan wie het ook aangaat</p>\r\n            \r\n            \r\n            \r\n            <p>Dit certificaat is bedoeld om aanspraak te maken op een Geen Bezwaarcertificaat (NoC) voor mevrouw/dhr. {employee_name} als zij/hij lid wordt en haar/zijn diensten verleent aan een andere organisatie. Het wordt ge&iuml;nformeerd als zij/hij al haar/zijn saldos heeft gewist en haar/zijn zekerheid heeft ontvangen van {app_name} Company.</p>\r\n            \r\n            \r\n            \r\n            <p>We wensen haar/hem veel succes in de toekomst.</p>\r\n            \r\n            \r\n            \r\n            <p>Eerlijk,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Handtekening</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(62,'pl','<h3 style=\"text-align: center;\">Certyfikat braku sprzeciwu</h3>\r\n            \r\n            \r\n            \r\n            <p>Data: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Do kogo to może dotyczyć</p>\r\n            \r\n            \r\n            \r\n            <p>Ten certyfikat służy do ubiegania się o Certyfikat No Objection Certificate (NoC) dla Pani/Pana {employee_name}, jeśli ona/ona dołącza i świadczy swoje usługi na rzecz jakiejkolwiek innej organizacji. Jest o tym informowany, ponieważ wyczyścił wszystkie swoje salda i otrzymał swoje zabezpieczenie od firmy {app_name}.</p>\r\n            \r\n            \r\n            \r\n            <p>Życzymy jej/jej powodzenia w przyszłości.</p>\r\n            \r\n            \r\n            \r\n            <p>Z poważaniem,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Podpis</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(63,'pt','<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\r\n                    \r\n            <p>Data: {date}</p>\r\n            \r\n            <p>A quem interessar</p>\r\n            \r\n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\r\n            \r\n            <p>Desejamos-lhe boa sorte no futuro.</p>\r\n            \r\n            <p>Sinceramente,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Assinatura</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(64,'ru','<h3 style=\"text-align: center;\">Сертификат об отсутствии возражений</h3>\r\n            \r\n            \r\n            \r\n            <p>Дата: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Кого бы это ни касалось</p>\r\n            \r\n            \r\n            \r\n            <p>Этот сертификат предназначен для получения Сертификата об отсутствии возражений (NoC) для г-жи / г-на {employee_name}, если она / он присоединяется и предоставляет свои услуги любой другой организации. Сообщается, что она/он очистила все свои балансы и получила свою безопасность от компании {app_name}.</p>\r\n            \r\n            \r\n            \r\n            <p>Мы желаем ей/ему удачи в будущем.</p>\r\n            \r\n            \r\n            \r\n            <p>Искренне,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Подпись</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(65,'tr','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>İtiraz Yok Belgesi</strong></span></p>\r\n            \r\n            <p>Tarih: {date}</p>\r\n            \r\n            <p>İlgilenebilecek Kişiye</p>\r\n            \r\n            <p>Bu sertifika, Bayan / Bay için bir İtiraz Yok Sertifikası (NoC) talep etmek içindir {employee_name} başka bir kuruluşa katılır ve hizmet verirse. Tüm bakiyelerini kapattığı ve teminatını aldığı bilgisi verilir {app_name} Şirket.</p>\r\n            \r\n            <p>Kendisine gelecekte iyi şanslar diliyoruz.</p>\r\n            \r\n            <p>Samimi olarak,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>İmza</p>\r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(66,'zh','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>无异议证书</strong></span></p>\r\n            \r\n            <p>日期: {date}</p>\r\n            \r\n            <p>致相关负责人</p>\r\n            \r\n            <p>此证书旨在为女士/先生申请无异议证书（NoC）。{employee_name} 如果她/他加入任何其他组织并向其提供服务。据了解，她/他已结清所有余额并从以下机构收到她/他的担保： {app_name} 公司.</p>\r\n            \r\n            <p>我们祝她/他未来好运.</p>\r\n            \r\n            <p>真挚地,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>签名</p>\r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(67,'he','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>אין תעודת התנגדות</strong></span></p>\r\n            \r\n            <p>תַאֲרִיך: {date}</p>\r\n            \r\n            <p>לכל מאן דבעי</p>\r\n            \r\n            <p>תעודה זו מיועדת לתבוע אישור ללא התנגדות (NoC) עבור גב / מר. {employee_name} אם הוא/ה מצטרף ומספק את שירותיו/ה לכל ארגון אחר. זה מודיע כפי שהיא / הוא פינה את כל היתרות שלה / שלו וקיבל את האבטחה שלה / שלו {app_name} חֶברָה.</p>\r\n            \r\n            <p>אנו מאחלים לו/לה בהצלחה בעתיד.</p>\r\n            \r\n            <p>בכנות,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>חֲתִימָה</p>\r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(68,'pt-br','<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\r\n                    \r\n            <p>Data: {date}</p>\r\n            \r\n            <p>A quem interessar</p>\r\n            \r\n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\r\n            \r\n            <p>Desejamos-lhe boa sorte no futuro.</p>\r\n            \r\n            <p>Sinceramente,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Assinatura</p>\r\n            \r\n            <p>{app_name}</p>',11,'2026-02-11 21:31:13','2026-02-11 21:31:13'),(69,'ar','<h3 style=\"text-align: center;\">شهادة عدم ممانعة</h3>\r\n            \r\n            \r\n            \r\n            <p>التاريخ: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>إلى من يهمه الأمر</p>\r\n            \r\n            \r\n            \r\n            <p>هذه الشهادة مخصصة للمطالبة بشهادة عدم ممانعة (NoC) للسيدة / السيد {employee_name} إذا انضمت إلى أي مؤسسة أخرى وقدمت خدماتها / خدماتها. يتم إبلاغه لأنه قام بتصفية جميع أرصدته واستلام أمانه من شركة {app_name}.</p>\r\n            \r\n            \r\n            \r\n            <p>نتمنى لها / لها التوفيق في المستقبل.</p>\r\n            \r\n            \r\n            \r\n            <p>بإخلاص،</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>التوقيع</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(70,'da','<h3 style=\"text-align: center;\">Ingen indsigelsesattest</h3>\r\n            \r\n            \r\n            \r\n            <p>Dato: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Til hvem det m&aring;tte vedr&oslash;re</p>\r\n            \r\n            \r\n            \r\n            <p>Dette certifikat er for at g&oslash;re krav p&aring; et No Objection Certificate (NoC) for Ms. / Mr. {employee_name}, hvis hun/han tilslutter sig og leverer sine tjenester til enhver anden organisation. Det informeres, da hun/han har udlignet alle sine saldi og modtaget sin sikkerhed fra {app_name}-virksomheden.</p>\r\n            \r\n            \r\n            \r\n            <p>Vi &oslash;nsker hende/ham held og lykke i fremtiden.</p>\r\n            \r\n            \r\n            \r\n            <p>Med venlig hilsen</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Underskrift</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(71,'de','<h3 style=\"text-align: center;\">Kein Einwand-Zertifikat</h3>\r\n            \r\n            \r\n            \r\n            <p>Datum {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Wen auch immer es betrifft</p>\r\n            \r\n            \r\n            \r\n            <p>Dieses Zertifikat soll ein Unbedenklichkeitszertifikat (NoC) f&uuml;r Frau / Herrn {employee_name} beanspruchen, wenn sie/er einer anderen Organisation beitritt und ihre/seine Dienste anbietet. Sie wird informiert, da sie/er alle ihre/seine Guthaben ausgeglichen und ihre/seine Sicherheit von der Firma {app_name} erhalten hat.</p>\r\n            \r\n            \r\n            \r\n            <p>Wir w&uuml;nschen ihr/ihm viel Gl&uuml;ck f&uuml;r die Zukunft.</p>\r\n            \r\n            \r\n            \r\n            <p>Aufrichtig,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Unterschrift</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(72,'en','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>No Objection Certificate</strong></span></p>\r\n            \r\n            <p>Date: {date}</p>\r\n            \r\n            <p>To Whomsoever It May Concern</p>\r\n            \r\n            <p>This certificate is to claim a No Objection Certificate (NoC) for Ms. / Mr. {employee_name} if she/he joins and provides her/his services to any other organization. It is informed as she/he has cleared all her/his balances and received her/his security from {app_name} Company.</p>\r\n            \r\n            <p>We wish her/him good luck in the future.</p>\r\n            \r\n            <p>Sincerely,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>Signature</p>\r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(73,'es','<h3 style=\"text-align: center;\">Certificado de conformidad</h3>\r\n            \r\n            \r\n            \r\n            <p>Fecha: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>A quien corresponda</p>\r\n            \r\n            \r\n            \r\n            <p>Este certificado es para reclamar un Certificado de No Objeci&oacute;n (NoC) para la Sra. / Sr. {employee_name} si ella / &eacute;l se une y brinda sus servicios a cualquier otra organizaci&oacute;n. Se informa que &eacute;l/ella ha liquidado todos sus saldos y recibido su seguridad de {app_name} Company.</p>\r\n            \r\n            \r\n            \r\n            <p>Le deseamos buena suerte en el futuro.</p>\r\n            \r\n            \r\n            \r\n            <p>Sinceramente,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Firma</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(74,'fr','<h3 style=\"text-align: center;\">Aucun certificat dopposition</h3>\r\n            \r\n            \r\n            <p>Date : {date}</p>\r\n            \r\n            \r\n            <p>&Agrave; toute personne concern&eacute;e</p>\r\n            \r\n            \r\n            <p>Ce certificat sert &agrave; r&eacute;clamer un certificat de non-objection (NoC) pour Mme / M. {employee_name} sil rejoint et fournit ses services &agrave; toute autre organisation. Il est inform&eacute; quil a sold&eacute; tous ses soldes et re&ccedil;u sa garantie de la part de la soci&eacute;t&eacute; {app_name}.</p>\r\n            \r\n            \r\n            <p>Nous lui souhaitons bonne chance pour lavenir.</p>\r\n            \r\n            \r\n            <p>Sinc&egrave;rement,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Signature</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(75,'id','<h3 style=\"text-align: center;\">Sertifikat Tidak Keberatan</h3>\r\n            \r\n            \r\n            \r\n            <p>Tanggal: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Kepada Siapa Pun Yang Memprihatinkan</p>\r\n            \r\n            \r\n            \r\n            <p>Sertifikat ini untuk mengklaim No Objection Certificate (NoC) untuk Ibu / Bapak {employee_name} jika dia bergabung dan memberikan layanannya ke organisasi lain mana pun. Diberitahukan karena dia telah melunasi semua saldonya dan menerima jaminannya dari Perusahaan {app_name}.</p>\r\n            \r\n            \r\n            \r\n            <p>Kami berharap dia sukses di masa depan.</p>\r\n            \r\n            \r\n            \r\n            <p>Sungguh-sungguh,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Tanda tangan</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(76,'it','<h3 style=\"text-align: center;\">Certificato di nulla osta</h3>\r\n            \r\n            \r\n            \r\n            <p>Data: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>A chi pu&ograve; interessare</p>\r\n            \r\n            \r\n            \r\n            <p>Questo certificato serve a richiedere un certificato di non obiezione (NoC) per la signora / il signor {employee_name} se si unisce e fornisce i suoi servizi a qualsiasi altra organizzazione. Viene informato in quanto ha liquidato tutti i suoi saldi e ricevuto la sua sicurezza dalla societ&agrave; {app_name}.</p>\r\n            \r\n            \r\n            \r\n            <p>Le auguriamo buona fortuna per il futuro.</p>\r\n            \r\n            \r\n            \r\n            <p>Cordiali saluti,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Firma</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(77,'ja','<h3 style=\"text-align: center;\">異議なし証明書</h3>\r\n            \r\n            \r\n            \r\n            <p>日付: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>関係者各位</p>\r\n            \r\n            \r\n            \r\n            <p>この証明書は、Ms. / Mr. {employee_name} が他の組織に参加してサービスを提供する場合に、異議なし証明書 (NoC) を請求するためのものです。彼女/彼/彼がすべての残高を清算し、{app_name} 会社から彼女/彼のセキュリティを受け取ったことが通知されます。</p>\r\n            \r\n            \r\n            \r\n            <p>彼女/彼の今後の幸運を祈っています。</p>\r\n            \r\n            \r\n            \r\n            <p>心から、</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>サイン</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(78,'nl','<h3 style=\"text-align: center;\">Geen bezwaarcertificaat</h3>\r\n            \r\n            \r\n            \r\n            <p>Datum: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Aan wie het ook aangaat</p>\r\n            \r\n            \r\n            \r\n            <p>Dit certificaat is bedoeld om aanspraak te maken op een Geen Bezwaarcertificaat (NoC) voor mevrouw/dhr. {employee_name} als zij/hij lid wordt en haar/zijn diensten verleent aan een andere organisatie. Het wordt ge&iuml;nformeerd als zij/hij al haar/zijn saldos heeft gewist en haar/zijn zekerheid heeft ontvangen van {app_name} Company.</p>\r\n            \r\n            \r\n            \r\n            <p>We wensen haar/hem veel succes in de toekomst.</p>\r\n            \r\n            \r\n            \r\n            <p>Eerlijk,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Handtekening</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(79,'pl','<h3 style=\"text-align: center;\">Certyfikat braku sprzeciwu</h3>\r\n            \r\n            \r\n            \r\n            <p>Data: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Do kogo to może dotyczyć</p>\r\n            \r\n            \r\n            \r\n            <p>Ten certyfikat służy do ubiegania się o Certyfikat No Objection Certificate (NoC) dla Pani/Pana {employee_name}, jeśli ona/ona dołącza i świadczy swoje usługi na rzecz jakiejkolwiek innej organizacji. Jest o tym informowany, ponieważ wyczyścił wszystkie swoje salda i otrzymał swoje zabezpieczenie od firmy {app_name}.</p>\r\n            \r\n            \r\n            \r\n            <p>Życzymy jej/jej powodzenia w przyszłości.</p>\r\n            \r\n            \r\n            \r\n            <p>Z poważaniem,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Podpis</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(80,'pt','<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\r\n                    \r\n            <p>Data: {date}</p>\r\n            \r\n            <p>A quem interessar</p>\r\n            \r\n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\r\n            \r\n            <p>Desejamos-lhe boa sorte no futuro.</p>\r\n            \r\n            <p>Sinceramente,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Assinatura</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(81,'ru','<h3 style=\"text-align: center;\">Сертификат об отсутствии возражений</h3>\r\n            \r\n            \r\n            \r\n            <p>Дата: {date}</p>\r\n            \r\n            \r\n            \r\n            <p>Кого бы это ни касалось</p>\r\n            \r\n            \r\n            \r\n            <p>Этот сертификат предназначен для получения Сертификата об отсутствии возражений (NoC) для г-жи / г-на {employee_name}, если она / он присоединяется и предоставляет свои услуги любой другой организации. Сообщается, что она/он очистила все свои балансы и получила свою безопасность от компании {app_name}.</p>\r\n            \r\n            \r\n            \r\n            <p>Мы желаем ей/ему удачи в будущем.</p>\r\n            \r\n            \r\n            \r\n            <p>Искренне,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Подпись</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(82,'tr','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>İtiraz Yok Belgesi</strong></span></p>\r\n            \r\n            <p>Tarih: {date}</p>\r\n            \r\n            <p>İlgilenebilecek Kişiye</p>\r\n            \r\n            <p>Bu sertifika, Bayan / Bay için bir İtiraz Yok Sertifikası (NoC) talep etmek içindir {employee_name} başka bir kuruluşa katılır ve hizmet verirse. Tüm bakiyelerini kapattığı ve teminatını aldığı bilgisi verilir {app_name} Şirket.</p>\r\n            \r\n            <p>Kendisine gelecekte iyi şanslar diliyoruz.</p>\r\n            \r\n            <p>Samimi olarak,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>İmza</p>\r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(83,'zh','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>无异议证书</strong></span></p>\r\n            \r\n            <p>日期: {date}</p>\r\n            \r\n            <p>致相关负责人</p>\r\n            \r\n            <p>此证书旨在为女士/先生申请无异议证书（NoC）。{employee_name} 如果她/他加入任何其他组织并向其提供服务。据了解，她/他已结清所有余额并从以下机构收到她/他的担保： {app_name} 公司.</p>\r\n            \r\n            <p>我们祝她/他未来好运.</p>\r\n            \r\n            <p>真挚地,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>签名</p>\r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(84,'he','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>אין תעודת התנגדות</strong></span></p>\r\n            \r\n            <p>תַאֲרִיך: {date}</p>\r\n            \r\n            <p>לכל מאן דבעי</p>\r\n            \r\n            <p>תעודה זו מיועדת לתבוע אישור ללא התנגדות (NoC) עבור גב / מר. {employee_name} אם הוא/ה מצטרף ומספק את שירותיו/ה לכל ארגון אחר. זה מודיע כפי שהיא / הוא פינה את כל היתרות שלה / שלו וקיבל את האבטחה שלה / שלו {app_name} חֶברָה.</p>\r\n            \r\n            <p>אנו מאחלים לו/לה בהצלחה בעתיד.</p>\r\n            \r\n            <p>בכנות,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>חֲתִימָה</p>\r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35'),(85,'pt-br','<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\r\n                    \r\n            <p>Data: {date}</p>\r\n            \r\n            <p>A quem interessar</p>\r\n            \r\n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\r\n            \r\n            <p>Desejamos-lhe boa sorte no futuro.</p>\r\n            \r\n            <p>Sinceramente,</p>\r\n            \r\n            <p>{employee_name}</p>\r\n            \r\n            <p>{designation}</p>\r\n            \r\n            <p>Assinatura</p>\r\n            \r\n            <p>{app_name}</p>',13,'2026-02-12 04:59:35','2026-02-12 04:59:35');
/*!40000 ALTER TABLE `noc_certificates` ENABLE KEYS */;
UNLOCK TABLES;

