INSERT INTO `notification_template_langs` VALUES (1,1,'ar','تم إنشاء قسيمة دفع بتاريخ {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(2,1,'da','Lønseddel genereret af {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(3,1,'de','Gehaltsabrechnung erstellt vom {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(4,1,'en','Payslip generated of {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(5,1,'es','Nómina generada de {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(6,1,'fr','Fiche de paie générée de {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(7,1,'it','Busta paga generata da {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(8,1,'ja','{year} の給与明細が作成されました。','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(9,1,'nl','Loonstrook gegenereerd van {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(10,1,'pl','Odcinek wypłaty wygenerowany za {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(11,1,'pt','Folha de pagamento gerada de {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(12,1,'ru','Расчетная ведомость создана за {year}.','{\n                    \"Year\": \"year\"\n                  }',1,'2026-02-05 05:36:40','2026-02-05 05:36:40'),(13,1,'tr','oluşturulan maaş bordrosu {year}.','{\n            