  `early_half_day` int(11) NOT NULL DEFAULT 0,
  `policy_summary_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`policy_summary_json`)),
  `present_effective` decimal(5,1) NOT NULL DEFAULT 0.0,
  `leave_effective` decimal(5,1) NOT NULL DEFAULT 0.0,
