CREATE TABLE `recruitment_requisitions` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `title` varchar(200) NOT NULL,
  `department_id` bigint(20) unsigned DEFAULT NULL,
  `designation_id` bigint(20) unsigned DEFAULT NULL,
  `branch_id` bigint(20) unsigned DEFAULT NULL,
  `skills` text NOT NULL,
  `experience` varchar(100) DEFAULT NULL,
  `positions` smallint(5) unsigned NOT NULL DEFAULT 1,
  `priority` enum('high','medium','low') NOT NULL DEFAULT 'medium',
  `reason` enum('replacement','new_hire','expansion') NOT NULL DEFAULT 'new_hire',
  `replacement_for` varchar(200) DEFAULT NULL,
  `salary_range` varchar(100) DEFAULT NULL,
  `location` varchar(200) DEFAULT NULL,
  `job_type` varchar(50) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `generated_jd` longtext DEFAULT NULL,
  `status` enum('draft','pending','approved','rejected','fulfilled') NOT NULL DEFAULT 'pending',
  `approval_chain` varchar(200) DEFAULT NULL,
  `current_approval_step` tinyint(3) unsigned NOT NULL DEFAULT 0,
  `needed_by` date DEFAULT NULL,
  `job_id` bigint(20) unsigned DEFAULT NULL,
  `created_by` bigint(20) unsigned NOT NULL,
  `raised_by_user_id` bigint(20) unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `recruitment_requisitions_created_by_status_index` (`created_by`,`status`),
  KEY `recruitment_requisitions_raised_by_user_id_index` (`raised_by_user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
