INSERT INTO `recruitment_requisitions` VALUES (3,'developer',2,1,6,'larvel','5',1,'medium','new_hire',NULL,'10lakh','mumbai','Full-time','tetsing','## About the Role\r\nWe are hiring a **developer** to join our team. This role is critical to our continued growth and you will work closely with cross-functional stakeholders to deliver measurable business impact.\r\n\r\n**Location:** mumbai  \r\n**Job Type:** Full-time  \r\n**Compensation:** 10lakh  \r\n**Needed By:** 01 Apr 2026  \r\n\r\n## Roles & Responsibilities\r\n- Design, develop and maintain backend services and APIs.\r\n- Write clean, well-tested, performant code following team standards.\r\n- Collaborate with product and design to deliver features end-to-end.\r\n- Troubleshoot production issues and contribute to post-mortems.\r\n\r\n## Requirements\r\n- Minimum experience: 5.\r\n- Hands-on experience with: larvel.\r\n- Strong understanding of OOP, design patterns and database fundamentals.\r\n- Experience writing automated tests and reviewing pull requests.\r\n- Familiarity with REST APIs, version control (Git) and CI/CD pipelines.\r\n\r\n## What We Offer\r\n- Competitive compensation and performance bonuses\r\n- Health insurance and wellness benefits\r\n- Learning & development budget\r\n- Flexible work culture and supportive team\r\n\r\n## Additional Notes\r\ntetsing','approved','hr,finance',0,'2026-04-01',2,6,12,'2026-04-27 08:53:57','2026-04-28 01:54:51'),(4,'Digital Marketing',16,1,6,'php','4',1,'medium','new_hire',NULL,'10lakh','mumbai','Full-time','tetsing','## About D&D Technology\n**D&D Technology** is a fast-growing organisation focused on building exceptional products and experiences for our customers. We invest in our people, foster a collaborative culture, and look for talent that takes ownership and drives impact.\n\n📍 JAIPUR,RAJASTHAN  ·  📞 8502837831\n\n## About the Role\nWe are hiring a **Digital Marketing** to join our team. This role is critical to our continued growth and you will work closely with cross-functional stakeholders to deliver measurable business impact.\n\n**Location:** mumbai  \n**Job Type:** Full-time  \n**Compensation:** 10lakh  \n**Needed By:** 01 May 2026  \n\n## Roles & Responsibilities\n- Plan and execute multi-channel marketing campaigns.\n- Own performance metrics — MQL volume, CPL, conversion.\n- Partner with content and design to ship campaign assets on time.\n- Design, develop and maintain backend services and APIs.\n- Write clean, well-tested, performant code following team standards.\n- Collaborate with product and design to deliver features end-to-end.\n- Troubleshoot production issues and contribute to post-mortems.\n\n## Requirements\n- Minimum experience: 4.\n- Hands-on experience with: php.\n- Hands-on with at least two of: SEO, paid ads, email, content.\n- Comfort with analytics tools (GA4, Mixpanel, etc.).\n- Strong copywriting and visual storytelling instincts.\n- Strong understanding of OOP, design patterns and database fundamentals.\n- Experience writing automated tests and reviewing pull requests.\n- Familiarity with REST APIs, version control (Git) and CI/CD pipelines.\n\n## What We Offer\n- Competitive compensation and performance bonuses\n- Health insurance and wellness benefits\n- Learning & development budget\n- Flexible work culture and supportive team\n\n## Additional Notes\ntetsing','approved','hr,finance',0,'2026-05-01',NULL,6,9,'2026-04-28 06:52:07','2026-04-28 01:54:51');
